import React, { useState, useEffect, useCallback, useTransition } from 'react';
import { useAuth } from './contexts/AuthContext';
import Register from './components/Register';
import Calendar from './components/Calendar';
import HolidayManagement from './components/HolidayManagement';
import VacationForm from './components/VacationForm';
import VacationPlanner from './components/VacationPlanner';
import './App.css';
// import './calendar-tailwind.css'; // Temporarily disabled to fix CSS conflicts

// Move API_BASE_URL outside component to avoid dependency issues
const API_BASE_URL = 'https://leave-tracking-backend.onrender.com';

function App() {
  const { user, token, loading, logout, fetchUserProfile } = useAuth();
  const [officialHolidays, setOfficialHolidays] = useState([]);
  const [vacations, setVacations] = useState([]);
  const [leaveBalances, setLeaveBalances] = useState({});
  const [showLogin, setShowLogin] = useState(null);
  const [calendarDate, setCalendarDate] = useState(new Date());
  const [, startHolidayTransition] = useTransition();
  // Loading states temporarily disabled to fix infinite loading issue

  // Simple fetch functions - no complex dependencies
  const fetchOfficialHolidays = useCallback(async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/holidays`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (response.ok) {
        const data = await response.json();
        setOfficialHolidays(data);
      }
      return response.ok; // Always return a value
    } catch (error) {
      console.error('Error fetching holidays:', error);
      return false; // Return false on error
    }
  }, [token]);

  const fetchVacations = useCallback(async () => {
    try {
      const response = await fetch(`${API_BASE_URL}/vacations`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (response.ok) {
        const data = await response.json();
        setVacations(data);
      } else {
        console.error('Failed to fetch vacations:', response.status, response.statusText);
      }
      return response.ok; // Always return a value
    } catch (error) {
      console.error('Error fetching vacations:', error);
      return false; // Return false on error
    }
  }, [token]);

  const fetchLeaveBalances = useCallback(async () => {
    try {
      if (!token) {
        console.error('No token available for leave balances request');
        return false; // Return false when no token
      }

      const response = await fetch(`${API_BASE_URL}/leave-balances`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();

        // Handle different possible data formats
        let processedData = data;
        if (Array.isArray(data)) {
          // If it's an array, convert to object format
          processedData = data.reduce((acc, item) => {
            acc[item.leaveType] = item.balance;
            return acc;
          }, {});
        } else if (data && typeof data === 'object') {
          // If it's already an object, use as is
          processedData = data;
        } else {
          // No valid data found
          processedData = {};
        }

        setLeaveBalances(processedData);
      } else {
        console.error('Failed to fetch leave balances:', response.status, response.statusText);
      }
      return response.ok; // Always return a value
    } catch (error) {
      console.error('Error fetching leave balances:', error);
      return false; // Return false on error
    }
  }, [token]);

  // Memoized holiday operation functions
  const handleAddHoliday = useCallback(async (holidayData) => {
    try {
      const response = await fetch(`${API_BASE_URL}/holidays`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(holidayData)
      });
      if (response.ok) {
        const newHoliday = await response.json();
        // Update local state immediately instead of refetching (low priority)
        startHolidayTransition(() => {
          setOfficialHolidays(prev => [...prev, newHoliday]);
        });
      } else {
        // If add fails, refresh to sync state
        console.error('Failed to add holiday, refreshing list...');
        fetchOfficialHolidays();
      }
    } catch (error) {
      console.error('Error adding holiday:', error);
      // On error, refresh to sync state
      fetchOfficialHolidays();
    }
  }, [token, fetchOfficialHolidays]);

  const handleDeleteHoliday = useCallback(async (holidayId) => {
    try {
      // Optimistic update - remove from UI immediately
      startHolidayTransition(() => {
        setOfficialHolidays(prev => {
          const index = prev.findIndex(holiday => holiday._id === holidayId);
          if (index === -1) return prev; // Holiday not found
          const newHolidays = [...prev];
          newHolidays.splice(index, 1);
          return newHolidays;
        });
      });

      // Then make the API call
      const response = await fetch(`${API_BASE_URL}/holidays/${holidayId}`, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (!response.ok) {
        if (response.status === 404) {
          // Holiday not found in database - refresh the list to sync
          console.warn('Holiday not found in database, refreshing list...');
          fetchOfficialHolidays();
        } else {
          // Other error - revert the optimistic update
          console.error('Failed to delete holiday from server');
          fetchOfficialHolidays(); // Refresh to sync state
        }
      }

      return response.ok; // Return success status
    } catch (error) {
      console.error('Error deleting holiday:', error);
      // Revert optimistic update on error by refreshing
      fetchOfficialHolidays();
      throw error; // Re-throw to be caught by the calling component
    }
  }, [token, fetchOfficialHolidays]);

  // Memoized calendar navigation handlers to avoid prop churn causing re-renders
  const handleCalendarNavigate = useCallback((action, newDate) => {
    setCalendarDate(newDate);
  }, []);

  const handleCalendarViewChange = useCallback((view) => {
    // no-op placeholder to keep stable reference if needed later
  }, []);

  // Load all data in parallel - simplified without loading states
  useEffect(() => {
    if (user && token) {
      // Simply run the API calls without loading states
      fetchUserProfile();
      fetchOfficialHolidays();
      fetchVacations();
      fetchLeaveBalances();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user, token]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col justify-center items-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600 mx-auto mb-4"></div>
            <h2 className="text-xl font-semibold text-gray-700 mb-2">Loading PlanWise</h2>
          <p className="text-gray-500">Please wait while we set up your account...</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-white">
        {/* Header */}
        <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex justify-between items-center h-16">
              <div className="flex items-center">
                <h1 className="text-2xl font-bold" style={{color: '#581c87'}}>
                  <span className="inline-block animate-pulse">P</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.1s'}}>l</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.2s'}}>a</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.3s'}}>n</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.4s'}}>W</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.5s'}}>i</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.6s'}}>s</span>
                  <span className="inline-block animate-pulse" style={{animationDelay: '0.7s'}}>e</span>
                </h1>
        </div>
              <div className="flex items-center space-x-4">
                {showLogin === null ? (
                  <>
                    <button
                      onClick={() => {
                        console.log('Sign In clicked, showLogin will be:', true);
                        setShowLogin(true);
                      }}
                      className="text-gray-600 hover:text-gray-900 font-medium"
                    >
                      Sign In
                    </button>
                    <button
                      onClick={() => {
                        console.log('Get Started clicked, showLogin will be:', false);
                        setShowLogin(false);
                      }}
                      className="bg-blue-600 text-white px-6 py-2 rounded-full font-medium hover:bg-blue-700 transition-colors"
                    >
                      Get Started
                    </button>
                  </>
                ) : (
                  <button
                    onClick={() => setShowLogin(null)}
                    className="flex items-center text-gray-600 hover:text-gray-900 font-medium"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                    </svg>
                    Back to Home
                  </button>
                )}
              </div>
            </div>
          </div>
        </header>

        {/* Main Content - Asana Homepage Template */}
        <div className="min-h-screen">
          {showLogin === null ? (
            <>
              {/* Hero Section with Light Pink Background */}
              <div className="bg-pink-50 py-20">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                  <div className="text-center">
                    <h1 className="text-4xl md:text-5xl font-bold mb-6 leading-tight" style={{color: '#581c87'}}>
                      🧠 PlanWise – AI-Powered Leave Planning
                      <br />
                      That Works Smarter
                    </h1>

                    <p className="text-lg mb-6 leading-relaxed max-w-3xl mx-auto" style={{color: '#1F2937'}}>
                      Save time, money, and mental bandwidth with intelligent leave planning. PlanWise uses AI to learn your patterns and optimize your time off—so you can rest better and plan smarter.
                    </p>

                    <div className="bg-white/20 backdrop-blur-sm rounded-2xl p-6 mb-8 max-w-4xl mx-auto border border-white/30">
                      <h2 className="text-xl font-semibold mb-4 text-center" style={{color: '#111827'}}>What PlanWise Delivers:</h2>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                        <div className="flex items-center space-x-3">
                          <span className="text-2xl">🔮</span>
                          <span style={{color: '#1F2937'}}>Smart predictions for the best vacation timing</span>
                        </div>
                        <div className="flex items-center space-x-3">
                          <span className="text-2xl">📆</span>
                          <span style={{color: '#1F2937'}}>Automatic detection of long weekend opportunities</span>
                        </div>
                        <div className="flex items-center space-x-3">
                          <span className="text-2xl">✈️</span>
                          <span style={{color: '#1F2937'}}>Real-time tracking of ticket prices and travel windows</span>
                        </div>
                        <div className="flex items-center space-x-3">
                          <span className="text-2xl">🧩</span>
                          <span style={{color: '#1F2937'}}>Personalized leave strategies based on your habits and goals</span>
                        </div>
                      </div>
                      <p className="text-center mt-4 text-sm" style={{color: '#334155'}}>
                        Whether you're planning a solo getaway or syncing with your team, PlanWise helps you make every day off count.
                      </p>
                      <p className="text-center mt-2 font-semibold text-sm" style={{color: '#581c87'}}>
                        Smarter leave. Happier teams. Better outcomes.
                      </p>
                    </div>

                    {/* CTA Buttons */}
                    <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
                      <button
                        onClick={() => setShowLogin(false)}
                        className="text-white px-6 py-3 rounded-lg font-semibold text-base transition-colors hover:opacity-90"
                        style={{backgroundColor: '#6b21a8'}}
                      >
